import React, { createContext, useContext, useState, useEffect, useMemo, useCallback } from 'react';
import translate from 'google-translate-api-x';

interface TranslationContextType {
  language: 'pt' | 'en' | 'es';
  setLanguage: (lang: 'pt' | 'en' | 'es') => void;
  t: (text: string) => string;
  isLoading: boolean;
}

const TranslationContext = createContext<TranslationContextType | null>(null);

export const TranslationProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [language, setLanguage] = useState<'pt' | 'en' | 'es'>('pt');
  const [translations, setTranslations] = useState<Record<string, string>>({});
  const [isLoading, setIsLoading] = useState(false);

  // Base Portuguese texts - memoized to prevent re-renders
  const baseTexts = useMemo((): Record<string, string> => ({
    'welcome': 'Bem-vindo ao enContact',
    'welcomeSubtitle': 'Sua plataforma de comunicação profissional',
    'email': 'Email',
    'password': 'Senha',
    'login': 'Entrar',
    'showPassword': 'Mostrar senha',
    'hidePassword': 'Ocultar senha',
    'inbox': 'Caixa de entrada',
    'sent': 'Enviados',
    'drafts': 'Rascunhos',
    'scheduled': 'Agendados',
    'archived': 'Arquivados',
    'trash': 'Lixeira',
    'search': 'Pesquisar...',
    'archive': 'Arquivar',
    'assign': 'Atribuir',
    'schedule': 'Agendar',
    'delete': 'Excluir',
    'permanentlyDelete': 'Excluir permanentemente',
    'archivedSuccessfully': '🎉 Arquivado com Sucesso!',
    'archivedMessage': '{{count}} item(ns) foram arquivados e agora estão organizados na aba Arquivados',
    'movedToTrash': '🗑️ Movido para Lixeira',
    'movedToTrashMessage': '{{count}} item(ns) foram movidos para a lixeira. Você pode recuperá-los na aba Lixeira',
    'permanentDeletion': '⚠️ Exclusão Permanente',
    'permanentDeletionMessage': '{{count}} item(ns) foram excluídos permanentemente. Esta ação não pode ser desfeita!',
    'assignedSuccessfully': '👤 Atribuído com Sucesso!',
    'assignedMessage': '{{count}} item(ns) foram atribuídos para responsáveis. Verifique o status em breve.',
    'scheduledSuccessfully': '📅 Agendado com Sucesso!',
    'scheduledMessage': '"{{title}}" foi agendado para {{date}} às {{time}}. Você pode encontrar na aba Agendamentos.',
    'noItems': 'Nenhum item encontrado',
    'noResults': 'Nenhum resultado encontrado',
    'loading': 'Carregando...',
    'all': 'Todos',
    'unread': 'Não lidos',
    'read': 'Lidos'
  }), []);

  // Translate texts function - memoized to prevent re-renders
  const translateTexts = useCallback(async () => {
    setIsLoading(true);
    const targetLang = language === 'en' ? 'en' : 'es';
    const newTranslations: Record<string, string> = {};

    try {
      // Translate each text
      for (const [key, text] of Object.entries(baseTexts)) {
        try {
          const result = await translate(text, { from: 'pt', to: targetLang });
          newTranslations[key] = result.text;
        } catch (error) {
          console.error(`Error translating ${key}:`, error);
          newTranslations[key] = text; // Fallback to original text
        }
      }
      setTranslations(newTranslations);
    } catch (error) {
      console.error('Translation error:', error);
      // Fallback to base texts
      setTranslations(baseTexts);
    } finally {
      setIsLoading(false);
    }
  }, [language, baseTexts]);

  // Translate texts when language changes
  useEffect(() => {
    if (language === 'pt') {
      // Use base texts directly for Portuguese
      setTranslations(baseTexts);
    } else {
      // Translate for other languages
      translateTexts();
    }
  }, [language, baseTexts, translateTexts]);

  const t = (key: string) => {
    return translations[key] || baseTexts[key] || key;
  };

  return (
    <TranslationContext.Provider value={{ language, setLanguage, t, isLoading }}>
      {children}
    </TranslationContext.Provider>
  );
};

export const useTranslation = () => {
  const context = useContext(TranslationContext);
  if (!context) {
    throw new Error('useTranslation must be used within a TranslationProvider');
  }
  return context;
};
